// src/App.js
import React from 'react';
import { HashRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import Sidebar from './components/SideBar';
import Home from './pages/Home';
import CompanyDirectory from './pages/CompanyDirectory';
import SkillsMapper from './pages/SkillsMapper';
import InterviewQuestions from './pages/InterviewQuestions';
import RoleExplorer from './pages/RoleExplorer';
import CompatibleUnitCourse from './pages/CompatibleUnitCourse';
import ThoriumCourse from './pages/ThoriumCourse';
import LFundCourse from './pages/LFundCourse';
import LFundQuiz from './pages/LFundQuiz';
import CompatibleUnitQuiz from './pages/CompatibleUnitQuiz';
import ThoriumQuiz from './pages/ThoriumQuiz';
import SubstationCourse from './pages/SubstationCourse';
import SubstationQuiz from './pages/SubstationQuiz';
import TxFundCourse from './pages/TxFundCourse';
import TxFundQuiz from './pages/TxFundQuiz';
import TxTestCourse from './pages/TxTestCourse';
import TxTestQuiz from './pages/TxTestQuiz';

import './App.css';

function App() {
  return (
    <Router>
      <div className="App">
        <Sidebar />
        <main className="main-content">
          <Routes>
            <Route path="/" element={<Home />} />
            <Route path="/company-directory" element={<CompanyDirectory />} />
            <Route path="/skills-mapper" element={<SkillsMapper />} />
            <Route path="/interview-questions" element={<InterviewQuestions />} />
            <Route path="/role-explorer" element={<RoleExplorer />} />
            <Route path="/compatible-unit-course-asdflhjjbufhjhjlgbbnmb686f8asdf" element={<CompatibleUnitCourse />} />
            <Route path='/compatible-unit-quiz-787KHJHFjlbnmnbvjhbgf1232' element={<CompatibleUnitQuiz />} />
            <Route path='/thorium-course-asdfhjljlbnhjerirouigf1232' element={<ThoriumCourse />} />
            <Route path='/thorium-quiz-ljhnmnmb987Fgjh32' element={<ThoriumQuiz />} />
            <Route path='/lfund-course-asdfhjlbnmnbvjhbgf1232' element={<LFundCourse />} />
            <Route path='/lfund-quiz' element={<LFundQuiz />} />
            <Route path='/substation-course-iuty8798jkjklfglkjoiu9' element={<SubstationCourse />} />
            <Route path='/substation-quiz-9876hgjh32' element={<SubstationQuiz />} />
            <Route path='/txfund-course-89jkjjgg98vmnbnbjkfg93246' element={<TxFundCourse />} />
            <Route path='/txfund-quiz-98lsg987JHGF76hgjh32' element={<TxFundQuiz />} />
            <Route path='/tx-test-course-98hgjhbmncmv987bfdg' element={<TxTestCourse />} />
            <Route path='/tx-test-quiz-KJsfmnsdf8v987bfdg' element={<TxTestQuiz />} />
            {/* Catch-all route - redirects unknown paths to homepage */}
            <Route path="*" element={<Navigate to="/" replace />} />
          </Routes>
        </main>
      </div>
    </Router>
  );
}

export default App;